import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.Nx1zvZTu.js";const b=JSON.parse('{"title":"Schemas","description":"","frontmatter":{},"headers":[],"relativePath":"reference/api/schemas.md","filePath":"reference/api/schemas.md"}'),a={name:"reference/api/schemas.md"};function n(i,t,c,s,h,l){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="schemas" tabindex="-1">Schemas <a class="header-anchor" href="#schemas" aria-label="Permalink to &quot;Schemas&quot;">​</a></h1><h3 id="capability" tabindex="-1">Capability <a class="header-anchor" href="#capability" aria-label="Permalink to &quot;Capability&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>yes</td><td>Capability name.</td></tr><tr><td><code>summary</code></td><td>string</td><td>yes</td><td>What it enables for downstream apps.</td></tr><tr><td><code>surfaces</code></td><td>string[]</td><td>yes</td><td>Endpoints / frames that expose it.</td></tr></tbody></table><h3 id="chunkflow" tabindex="-1">ChunkFlow <a class="header-anchor" href="#chunkflow" aria-label="Permalink to &quot;ChunkFlow&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>yes</td><td>Flow name, e.g. &#39;upload&#39; or &#39;read&#39;.</td></tr><tr><td><code>summary</code></td><td>string</td><td>yes</td><td>What the flow does.</td></tr><tr><td><code>sequence</code></td><td>string[]</td><td>yes</td><td>Ordered wire steps for the flow.</td></tr></tbody></table><h3 id="configfield" tabindex="-1">ConfigField <a class="header-anchor" href="#configfield" aria-label="Permalink to &quot;ConfigField&quot;">​</a></h3><p>One config field reflected from an Interface.Config class.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>yes</td><td>Config field name.</td></tr><tr><td><code>type</code></td><td>string</td><td>yes</td><td>Python type annotation as string.</td></tr><tr><td><code>default</code></td><td>any</td><td>yes</td><td>Default value, or null if required.</td></tr><tr><td><code>required</code></td><td>boolean</td><td>yes</td><td>True when the field has no default.</td></tr><tr><td><code>fields</code></td><td>any</td><td>no</td><td>Sub-fields when the annotation is a nested config model (recursively reflected), so clients can render structured editors.</td></tr></tbody></table><h3 id="configfilter" tabindex="-1">ConfigFilter <a class="header-anchor" href="#configfilter" aria-label="Permalink to &quot;ConfigFilter&quot;">​</a></h3><p>One operator clause over a config json path (range/equality/membership).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code></td><td>string</td><td>yes</td><td>Dotted path into the config layer, e.g. &#39;a.b&#39;.</td></tr><tr><td><code>op</code></td><td>ConfigOp</td><td>no</td><td></td></tr><tr><td><code>value</code></td><td>any</td><td>no</td><td></td></tr></tbody></table><h3 id="configlayer" tabindex="-1">ConfigLayer <a class="header-anchor" href="#configlayer" aria-label="Permalink to &quot;ConfigLayer&quot;">​</a></h3><p>Enum: <code>default</code>, <code>version</code>, <code>update</code>, <code>resolved</code></p><h3 id="configmatch" tabindex="-1">ConfigMatch <a class="header-anchor" href="#configmatch" aria-label="Permalink to &quot;ConfigMatch&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>layer</code></td><td>ConfigLayer</td><td>no</td><td></td></tr><tr><td><code>filters</code></td><td>ConfigFilter[]</td><td>no</td><td></td></tr></tbody></table><h3 id="configop" tabindex="-1">ConfigOp <a class="header-anchor" href="#configop" aria-label="Permalink to &quot;ConfigOp&quot;">​</a></h3><p>Enum: <code>eq</code>, <code>ne</code>, <code>lt</code>, <code>lte</code>, <code>gt</code>, <code>gte</code>, <code>in</code>, <code>contains</code></p><h3 id="createinterfacerequest" tabindex="-1">CreateInterfaceRequest <a class="header-anchor" href="#createinterfacerequest" aria-label="Permalink to &quot;CreateInterfaceRequest&quot;">​</a></h3><p>Create (materialize) an Interface, optionally with a client-supplied id.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Module path to instantiate.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Passed to Interface.make().</td></tr><tr><td><code>uuid</code></td><td>any</td><td>no</td><td>Client-supplied id (e.g. content hash). Idempotent: creating again with the same id returns the existing instance unchanged.</td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td>Optional mutable label to set on creation.</td></tr><tr><td><code>meta</code></td><td>object</td><td>no</td><td></td></tr></tbody></table><h3 id="datastatusresponse" tabindex="-1">DataStatusResponse <a class="header-anchor" href="#datastatusresponse" aria-label="Permalink to &quot;DataStatusResponse&quot;">​</a></h3><p>Whether a run&#39;s stored data is readable now (local / remote / evicted).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>available</code></td><td>boolean</td><td>yes</td><td>True when the working directory is mounted.</td></tr><tr><td><code>mounted</code></td><td>boolean</td><td>yes</td><td></td></tr><tr><td><code>storage_uri</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>local_uri</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>bytes_missing</code></td><td>boolean</td><td>no</td><td></td></tr></tbody></table><h3 id="dispatchinterface" tabindex="-1">DispatchInterface <a class="header-anchor" href="#dispatchinterface" aria-label="Permalink to &quot;DispatchInterface&quot;">​</a></h3><p>One interface to add to an Execution.</p><p>Carries the ordered <code>with</code>-context it runs under.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Interface module path.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td></td></tr><tr><td><code>context</code></td><td>InterfaceRef[]</td><td>no</td><td>Ordered <code>with</code>-contexts the interface is created under; any interface (Scope is one kind). Entered in order, exited in reverse (LIFO), exactly like the CLI&#39;s element chain. Order is significant.</td></tr></tbody></table><h3 id="dispatchrequest" tabindex="-1">DispatchRequest <a class="header-anchor" href="#dispatchrequest" aria-label="Permalink to &quot;DispatchRequest&quot;">​</a></h3><p>Create/reuse an Execution and dispatch interfaces into it.</p><p>Mirrors <code>with Project(request): Execution.add([with ctx: ...]).dispatch()</code> Here, Project is the request&#39;s ambient project (<code>?project=</code>); the Execution is the container; each interface carries its own ordered context chain.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>execution</code></td><td>any</td><td>no</td><td>The Execution container interface; omit for a default Execution().</td></tr><tr><td><code>execution_ref</code></td><td>any</td><td>no</td><td>Reuse/resume a specific Execution instance (its uuid) instead of creating one.</td></tr><tr><td><code>interfaces</code></td><td>DispatchInterface[]</td><td>no</td><td>Interfaces to add to the Execution, each with its <code>with</code>-context stack.</td></tr></tbody></table><h3 id="executioninfo" tabindex="-1">ExecutionInfo <a class="header-anchor" href="#executioninfo" aria-label="Permalink to &quot;ExecutionInfo&quot;">​</a></h3><p>An Execution run-record, the only kind that carries lifecycle status.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>string</td><td>yes</td><td>Unique execution identifier.</td></tr><tr><td><code>module</code></td><td>any</td><td>no</td><td>Project-relative module path.</td></tr><tr><td><code>config</code></td><td>object</td><td>yes</td><td>Resolved execution configuration.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Compact version list.</td></tr><tr><td><code>cli</code></td><td>string</td><td>no</td><td>Reproduction command (module + version).</td></tr><tr><td><code>seed</code></td><td>integer</td><td>yes</td><td>Random seed for this execution.</td></tr><tr><td><code>nickname</code></td><td>string</td><td>yes</td><td>Human-readable execution nickname.</td></tr><tr><td><code>resources</code></td><td>any</td><td>no</td><td>Requested compute resources.</td></tr><tr><td><code>parent_uuid</code></td><td>string</td><td>yes</td><td>Uuid of the parent Interface for this run.</td></tr><tr><td><code>is_started</code></td><td>boolean</td><td>yes</td><td>True when started_at has been written.</td></tr><tr><td><code>is_active</code></td><td>boolean</td><td>yes</td><td>True when heartbeat is recent and not finished.</td></tr><tr><td><code>is_finished</code></td><td>boolean</td><td>yes</td><td>True when finished_at has been written.</td></tr><tr><td><code>is_incomplete</code></td><td>boolean</td><td>yes</td><td>True when started but not live.</td></tr><tr><td><code>is_live</code></td><td>boolean</td><td>no</td><td>True when the heartbeat is recent.</td></tr><tr><td><code>is_resumed</code></td><td>boolean</td><td>no</td><td>True when the run was resumed at least once.</td></tr><tr><td><code>started_at</code></td><td>any</td><td>no</td><td>ISO-8601 start timestamp.</td></tr><tr><td><code>resumed_at</code></td><td>any</td><td>no</td><td>ISO-8601 last resume timestamp.</td></tr><tr><td><code>finished_at</code></td><td>any</td><td>no</td><td>ISO-8601 finish timestamp.</td></tr><tr><td><code>heartbeat_at</code></td><td>any</td><td>no</td><td>ISO-8601 last heartbeat timestamp.</td></tr><tr><td><code>created_at</code></td><td>string</td><td>yes</td><td>ISO-8601 creation timestamp.</td></tr><tr><td><code>created_by</code></td><td>any</td><td>no</td><td>User attributed as creator when first materialized.</td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td>Optional mutable, human-facing label.</td></tr></tbody></table><h3 id="findrequest" tabindex="-1">FindRequest <a class="header-anchor" href="#findrequest" aria-label="Permalink to &quot;FindRequest&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>module</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>kind</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>created_by</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>parent_id</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>identity_key</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>predicate_key</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>predicate</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>config</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>sort</code></td><td>SortSpec[]</td><td>no</td><td></td></tr><tr><td><code>include_hidden</code></td><td>boolean</td><td>no</td><td></td></tr><tr><td><code>include_bytes_missing</code></td><td>boolean</td><td>no</td><td></td></tr><tr><td><code>record_id_suffix</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>limit</code></td><td>integer</td><td>no</td><td></td></tr><tr><td><code>offset</code></td><td>integer</td><td>no</td><td></td></tr><tr><td><code>include_status</code></td><td>boolean</td><td>no</td><td></td></tr></tbody></table><h3 id="framefield" tabindex="-1">FrameField <a class="header-anchor" href="#framefield" aria-label="Permalink to &quot;FrameField&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>yes</td><td>Field name on the JSON frame.</td></tr><tr><td><code>type</code></td><td>string</td><td>yes</td><td>JSON type, e.g. string, object, bool.</td></tr><tr><td><code>required</code></td><td>boolean</td><td>no</td><td>Whether the field is required.</td></tr><tr><td><code>description</code></td><td>string</td><td>yes</td><td>What the field means.</td></tr></tbody></table><h3 id="graphedge" tabindex="-1">GraphEdge <a class="header-anchor" href="#graphedge" aria-label="Permalink to &quot;GraphEdge&quot;">​</a></h3><p>A typed, directed edge referencing nodes by uuid.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>source</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>target</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>rel</code></td><td>string</td><td>yes</td><td>derivation | context | uses | runs | manifest | …</td></tr></tbody></table><h3 id="graphnode" tabindex="-1">GraphNode <a class="header-anchor" href="#graphnode" aria-label="Permalink to &quot;GraphNode&quot;">​</a></h3><p>One node in a provenance graph.</p><p><code>attributes</code> is the per-kind open facet (== <code>Interface.on_provenance_attributes()</code>): an Execution carries seed/timing, a Manifest its entries, a recipe interface its config layers + context.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>kind</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>module</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td></td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>attributes</code></td><td>object</td><td>no</td><td></td></tr></tbody></table><h3 id="httpvalidationerror" tabindex="-1">HTTPValidationError <a class="header-anchor" href="#httpvalidationerror" aria-label="Permalink to &quot;HTTPValidationError&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>detail</code></td><td>ValidationError[]</td><td>no</td><td></td></tr></tbody></table><h3 id="healthresponse" tabindex="-1">HealthResponse <a class="header-anchor" href="#healthresponse" aria-label="Permalink to &quot;HealthResponse&quot;">​</a></h3><p>Server health summary.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>status</code></td><td>string</td><td>yes</td><td>Health status literal.</td></tr><tr><td><code>version</code></td><td>string</td><td>yes</td><td>Installed machinable version.</td></tr><tr><td><code>project</code></td><td>any</td><td>no</td><td>Default (launch) project directory, if any.</td></tr><tr><td><code>projects</code></td><td>string[]</td><td>no</td><td>Project directories the server currently holds state for.</td></tr><tr><td><code>executions_active</code></td><td>integer</td><td>yes</td><td>Active Execution records in the default project.</td></tr><tr><td><code>uptime_seconds</code></td><td>number</td><td>yes</td><td>Seconds since the API server started.</td></tr></tbody></table><h3 id="interfacecallrequest" tabindex="-1">InterfaceCallRequest <a class="header-anchor" href="#interfacecallrequest" aria-label="Permalink to &quot;InterfaceCallRequest&quot;">​</a></h3><p>One-shot synchronous Interface method call over REST.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Module path or existing interface uuid.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Passed to Interface.make() when target is a module path.</td></tr><tr><td><code>meta</code></td><td>object</td><td>no</td><td>Optional metadata stored with a newly created interface.</td></tr><tr><td><code>method</code></td><td>string</td><td>yes</td><td>Public method name to invoke.</td></tr><tr><td><code>args</code></td><td>array</td><td>no</td><td>Positional arguments.</td></tr><tr><td><code>kwargs</code></td><td>object</td><td>no</td><td>Keyword arguments.</td></tr></tbody></table><h3 id="interfacehook" tabindex="-1">InterfaceHook <a class="header-anchor" href="#interfacehook" aria-label="Permalink to &quot;InterfaceHook&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>yes</td><td>Method/attribute the project interface defines.</td></tr><tr><td><code>signature</code></td><td>string</td><td>yes</td><td>Python signature.</td></tr><tr><td><code>description</code></td><td>string</td><td>yes</td><td>When machinable invokes it and contract.</td></tr></tbody></table><h3 id="interfaceinfo" tabindex="-1">InterfaceInfo <a class="header-anchor" href="#interfaceinfo" aria-label="Permalink to &quot;InterfaceInfo&quot;">​</a></h3><p>A materialized Interface entry (pure data node, no lifecycle status).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>string</td><td>yes</td><td>Unique interface identifier.</td></tr><tr><td><code>module</code></td><td>any</td><td>no</td><td>Project-relative module path.</td></tr><tr><td><code>kind</code></td><td>string</td><td>yes</td><td>Interface kind, e.g. Interface or Project.</td></tr><tr><td><code>config</code></td><td>object</td><td>yes</td><td>Resolved configuration for this interface.</td></tr><tr><td><code>predicate</code></td><td>object</td><td>yes</td><td>Predicate dict used for index lookup.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Compact version list (~versions + override dicts).</td></tr><tr><td><code>cli</code></td><td>string</td><td>no</td><td>Reproduction command: module + compact version as a CLI string.</td></tr><tr><td><code>cached</code></td><td>boolean</td><td>yes</td><td>True when computation for this interface has finished.</td></tr><tr><td><code>created_at</code></td><td>string</td><td>yes</td><td>ISO-8601 creation timestamp recorded at materialization.</td></tr><tr><td><code>created_by</code></td><td>any</td><td>no</td><td>User attributed as creator when first materialized.</td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td>Optional mutable, human-facing label (config stays immutable).</td></tr><tr><td><code>meta</code></td><td>object</td><td>no</td><td>Client metadata supplied on WS connect.</td></tr><tr><td><code>execution_count</code></td><td>integer</td><td>yes</td><td>Number of Execution children in the index.</td></tr><tr><td><code>latest_execution_uuid</code></td><td>any</td><td>no</td><td>Uuid of the most recent Execution child, if any.</td></tr></tbody></table><h3 id="interfaceref" tabindex="-1">InterfaceRef <a class="header-anchor" href="#interfaceref" aria-label="Permalink to &quot;InterfaceRef&quot;">​</a></h3><p>A uniform reference to any interface.</p><p><code>target</code> (module path) + compact <code>version</code>.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Module path (or uuid).</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Compact version (~versions + override dicts).</td></tr></tbody></table><h3 id="lifecyclerequest" tabindex="-1">LifecycleRequest <a class="header-anchor" href="#lifecyclerequest" aria-label="Permalink to &quot;LifecycleRequest&quot;">​</a></h3><p>Content-addressed lifecycle lookup for a compact version (no run/materialize).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Module path to look up by content.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Compact version (~versions + overrides).</td></tr><tr><td><code>context</code></td><td>InterfaceRef[]</td><td>no</td><td>Ordered <code>with</code>-contexts the config is created under (Scope or any interface). Entered before lookup so a scoped config resolves to its scoped identity and must match what it was dispatched under.</td></tr></tbody></table><h3 id="lifecycleresponse" tabindex="-1">LifecycleResponse <a class="header-anchor" href="#lifecycleresponse" aria-label="Permalink to &quot;LifecycleResponse&quot;">​</a></h3><p>The compute lifecycle state for a config, derived purely from the index.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Module path that was looked up.</td></tr><tr><td><code>module</code></td><td>any</td><td>no</td><td>Resolved module path.</td></tr><tr><td><code>uuid</code></td><td>any</td><td>no</td><td>Materialized interface id, or null when never created (draft).</td></tr><tr><td><code>status</code></td><td>LifecycleStatus</td><td>yes</td><td>draft | running | cached | failed.</td></tr><tr><td><code>cached</code></td><td>boolean</td><td>no</td><td>True when a finished result is available to read.</td></tr><tr><td><code>execution_uuid</code></td><td>any</td><td>no</td><td>Latest Execution run id, if any.</td></tr></tbody></table><h3 id="lifecyclestatus" tabindex="-1">LifecycleStatus <a class="header-anchor" href="#lifecyclestatus" aria-label="Permalink to &quot;LifecycleStatus&quot;">​</a></h3><p>Where a content-addressed config sits in its compute lifecycle.</p><p>Enum: <code>draft</code>, <code>running</code>, <code>cached</code>, <code>failed</code></p><h3 id="moduleschema" tabindex="-1">ModuleSchema <a class="header-anchor" href="#moduleschema" aria-label="Permalink to &quot;ModuleSchema&quot;">​</a></h3><p>Config schema for one discoverable Interface module.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>module</code></td><td>string</td><td>yes</td><td>Project-relative dotted module path.</td></tr><tr><td><code>kind</code></td><td>string</td><td>yes</td><td>Interface kind for the discovered class.</td></tr><tr><td><code>doc</code></td><td>any</td><td>no</td><td>Class docstring, if present.</td></tr><tr><td><code>config_fields</code></td><td>ConfigField[]</td><td>yes</td><td>Reflected Config fields for form rendering.</td></tr><tr><td><code>versions</code></td><td>string[]</td><td>yes</td><td>Named version methods exposed by the class.</td></tr><tr><td><code>version_methods</code></td><td>VersionMethod[]</td><td>no</td><td>Version methods with signature + docstring (the ~version vocab).</td></tr><tr><td><code>widget</code></td><td>any</td><td>no</td><td>Widget frontend descriptor when the class ships one.</td></tr><tr><td><code>source_file</code></td><td>any</td><td>no</td><td>Project-relative source file of the class (readable via GET /v1/source/{path}), when inside the project.</td></tr><tr><td><code>source_line</code></td><td>any</td><td>no</td><td>1-based line of the class definition.</td></tr></tbody></table><h3 id="outputchunk" tabindex="-1">OutputChunk <a class="header-anchor" href="#outputchunk" aria-label="Permalink to &quot;OutputChunk&quot;">​</a></h3><p>A bounded byte-window of a run&#39;s output log.</p><p>Clients follow a log incrementally: first request a <code>tail</code>, then poll with <code>offset=size</code> to fetch only appended bytes — never the whole file.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>output</code></td><td>any</td><td>yes</td><td>The window&#39;s text (utf-8, replacement-decoded), or null when no output exists yet.</td></tr><tr><td><code>offset</code></td><td>integer</td><td>no</td><td>Byte position where the returned window starts.</td></tr><tr><td><code>size</code></td><td>integer</td><td>no</td><td>Total size of the log in bytes, for follow-up offset requests.</td></tr></tbody></table><h3 id="projectindex" tabindex="-1">ProjectIndex <a class="header-anchor" href="#projectindex" aria-label="Permalink to &quot;ProjectIndex&quot;">​</a></h3><p>Index of discoverable Interface modules.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>project</code></td><td>string</td><td>yes</td><td>Absolute project directory path.</td></tr><tr><td><code>modules</code></td><td>ProjectModule[]</td><td>yes</td><td>Discoverable Interface subclasses.</td></tr></tbody></table><h3 id="projectmodule" tabindex="-1">ProjectModule <a class="header-anchor" href="#projectmodule" aria-label="Permalink to &quot;ProjectModule&quot;">​</a></h3><p>Discoverable Interface module in the connected project.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>module</code></td><td>string</td><td>yes</td><td>Project-relative dotted module path.</td></tr><tr><td><code>kind</code></td><td>string</td><td>yes</td><td>Interface kind for the discovered class.</td></tr><tr><td><code>doc</code></td><td>any</td><td>no</td><td>Class docstring, if present.</td></tr><tr><td><code>widget</code></td><td>boolean</td><td>no</td><td>True when the class ships a widget frontend.</td></tr></tbody></table><h3 id="protocoldoc" tabindex="-1">ProtocolDoc <a class="header-anchor" href="#protocoldoc" aria-label="Permalink to &quot;ProtocolDoc&quot;">​</a></h3><p>The non-OpenAPI half of the contract: WebSocket protocol + hooks.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>protocol_version</code></td><td>string</td><td>yes</td><td>Wire protocol version.</td></tr><tr><td><code>transport</code></td><td>object</td><td>yes</td><td>Transport notes (control plane vs data plane).</td></tr><tr><td><code>headers</code></td><td>FrameField[]</td><td>yes</td><td>Cross-cutting request headers (project/user/interpreter).</td></tr><tr><td><code>ws_endpoints</code></td><td>object</td><td>yes</td><td>WebSocket routes and what they connect to.</td></tr><tr><td><code>ws_frames</code></td><td>WSFrame[]</td><td>yes</td><td>Every WebSocket frame type.</td></tr><tr><td><code>chunk_flows</code></td><td>ChunkFlow[]</td><td>yes</td><td>Binary upload and read sequences.</td></tr><tr><td><code>interface_hooks</code></td><td>InterfaceHook[]</td><td>yes</td><td>Hooks a project Interface implements for the data plane.</td></tr><tr><td><code>capabilities</code></td><td>Capability[]</td><td>yes</td><td>High-level capability map for downstream consumers.</td></tr></tbody></table><h3 id="provenancegraph" tabindex="-1">ProvenanceGraph <a class="header-anchor" href="#provenancegraph" aria-label="Permalink to &quot;ProvenanceGraph&quot;">​</a></h3><p>Normalized node-link DAG: how a result came to be.</p><p>Nodes appear once; shared nodes (a Manifest used by many runs) are referenced by many edges, never duplicated. Every edge&#39;s <code>source</code>/<code>target</code> is guaranteed present in <code>nodes</code>.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>root</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>nodes</code></td><td>GraphNode[]</td><td>no</td><td></td></tr><tr><td><code>links</code></td><td>GraphEdge[]</td><td>no</td><td></td></tr><tr><td><code>truncated</code></td><td>boolean</td><td>no</td><td>True when a node cap bounded the walk.</td></tr></tbody></table><h3 id="relateditem" tabindex="-1">RelatedItem <a class="header-anchor" href="#relateditem" aria-label="Permalink to &quot;RelatedItem&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>module</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>kind</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td></td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td></td></tr></tbody></table><h3 id="relatedresponse" tabindex="-1">RelatedResponse <a class="header-anchor" href="#relatedresponse" aria-label="Permalink to &quot;RelatedResponse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>related</code></td><td>RelatedItem[]</td><td>yes</td><td></td></tr></tbody></table><h3 id="remotesresponse" tabindex="-1">RemotesResponse <a class="header-anchor" href="#remotesresponse" aria-label="Permalink to &quot;RemotesResponse&quot;">​</a></h3><p>Shareable interfaces the project resolves by URL (slurm, globus, …).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>remotes</code></td><td>object</td><td>no</td><td>module path → source URL (or [source, *dependencies]).</td></tr></tbody></table><h3 id="resolverequest" tabindex="-1">ResolveRequest <a class="header-anchor" href="#resolverequest" aria-label="Permalink to &quot;ResolveRequest&quot;">​</a></h3><p>Dry-run a compact version: expand it to resolved config without running.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>target</code></td><td>string</td><td>yes</td><td>Module path to instantiate.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Compact version (~versions + overrides).</td></tr></tbody></table><h3 id="resolveresponse" tabindex="-1">ResolveResponse <a class="header-anchor" href="#resolveresponse" aria-label="Permalink to &quot;ResolveResponse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>module</code></td><td>any</td><td>no</td><td>Module path.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>The compact version as given.</td></tr><tr><td><code>config</code></td><td>object</td><td>yes</td><td>Resolved configuration.</td></tr><tr><td><code>predicate</code></td><td>object</td><td>no</td><td>Computed predicate.</td></tr><tr><td><code>cli</code></td><td>string</td><td>yes</td><td>Reproduction command (module + version).</td></tr></tbody></table><h3 id="searchitem" tabindex="-1">SearchItem <a class="header-anchor" href="#searchitem" aria-label="Permalink to &quot;SearchItem&quot;">​</a></h3><p>A lightweight search hit over the interface index.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>string</td><td>yes</td><td>Interface uuid.</td></tr><tr><td><code>module</code></td><td>any</td><td>no</td><td>Module path.</td></tr><tr><td><code>kind</code></td><td>string</td><td>yes</td><td>Interface kind.</td></tr><tr><td><code>config</code></td><td>object</td><td>no</td><td>Resolved configuration.</td></tr><tr><td><code>version</code></td><td>array</td><td>no</td><td>Compact version (~versions + overrides).</td></tr><tr><td><code>created_at_ns</code></td><td>integer</td><td>yes</td><td>Creation timestamp (ns).</td></tr><tr><td><code>created_by</code></td><td>any</td><td>no</td><td>Creator.</td></tr><tr><td><code>label</code></td><td>any</td><td>no</td><td>Mutable label.</td></tr><tr><td><code>status</code></td><td>any</td><td>no</td><td>draft|running|cached|failed for the latest run (with include_status).</td></tr><tr><td><code>run_count</code></td><td>any</td><td>no</td><td>Recorded runs (with include_status).</td></tr></tbody></table><h3 id="searchresponse" tabindex="-1">SearchResponse <a class="header-anchor" href="#searchresponse" aria-label="Permalink to &quot;SearchResponse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>items</code></td><td>SearchItem[]</td><td>yes</td><td></td></tr><tr><td><code>total</code></td><td>integer</td><td>yes</td><td>Total matches ignoring limit/offset.</td></tr></tbody></table><h3 id="setlabelrequest" tabindex="-1">SetLabelRequest <a class="header-anchor" href="#setlabelrequest" aria-label="Permalink to &quot;SetLabelRequest&quot;">​</a></h3><p>Set/replace an interface&#39;s mutable label (FCFS / last-write-wins).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>label</code></td><td>any</td><td>yes</td><td>New label value, or null to clear.</td></tr></tbody></table><h3 id="sortspec" tabindex="-1">SortSpec <a class="header-anchor" href="#sortspec" aria-label="Permalink to &quot;SortSpec&quot;">​</a></h3><p>A single ORDER BY term, over an index column or a config json path.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>by</code></td><td>string</td><td>no</td><td>Index column, or a config json path when config_layer is set.</td></tr><tr><td><code>config_layer</code></td><td>any</td><td>no</td><td>When set, <code>by</code> is a json path into this config layer.</td></tr><tr><td><code>direction</code></td><td>string</td><td>no</td><td>&quot;asc&quot; or &quot;desc&quot;.</td></tr></tbody></table><h3 id="sourcefile" tabindex="-1">SourceFile <a class="header-anchor" href="#sourcefile" aria-label="Permalink to &quot;SourceFile&quot;">​</a></h3><p>One source file under the project tree.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code></td><td>string</td><td>yes</td><td>Project-relative file path (forward slashes).</td></tr><tr><td><code>module</code></td><td>string</td><td>yes</td><td>Dotted module path the file imports as.</td></tr><tr><td><code>size</code></td><td>integer</td><td>yes</td><td>File size in bytes.</td></tr><tr><td><code>mtime_ns</code></td><td>integer</td><td>yes</td><td>Last-modified time (ns since epoch).</td></tr></tbody></table><h3 id="sourcefilecontent" tabindex="-1">SourceFileContent <a class="header-anchor" href="#sourcefilecontent" aria-label="Permalink to &quot;SourceFileContent&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code></td><td>string</td><td>yes</td><td>Project-relative file path.</td></tr><tr><td><code>module</code></td><td>string</td><td>yes</td><td>Dotted module path the file imports as.</td></tr><tr><td><code>content</code></td><td>string</td><td>yes</td><td>Full file content.</td></tr><tr><td><code>etag</code></td><td>string</td><td>yes</td><td>MD5 of the content (also returned as ETag header).</td></tr><tr><td><code>size</code></td><td>integer</td><td>yes</td><td>Content size in bytes.</td></tr></tbody></table><h3 id="sourcelistresponse" tabindex="-1">SourceListResponse <a class="header-anchor" href="#sourcelistresponse" aria-label="Permalink to &quot;SourceListResponse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>base_dir</code></td><td>string</td><td>yes</td><td>Absolute base directory the API is confined to.</td></tr><tr><td><code>files</code></td><td>SourceFile[]</td><td>yes</td><td></td></tr></tbody></table><h3 id="sourcemoverequest" tabindex="-1">SourceMoveRequest <a class="header-anchor" href="#sourcemoverequest" aria-label="Permalink to &quot;SourceMoveRequest&quot;">​</a></h3><p>Atomic rename/move within the base directory (e.g. rename an interface).</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>from</code></td><td>string</td><td>yes</td><td>Existing source path.</td></tr><tr><td><code>to</code></td><td>string</td><td>yes</td><td>Destination source path (must not exist).</td></tr></tbody></table><h3 id="sourcewriterequest" tabindex="-1">SourceWriteRequest <a class="header-anchor" href="#sourcewriterequest" aria-label="Permalink to &quot;SourceWriteRequest&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>content</code></td><td>string</td><td>yes</td><td>Full new file content (overwrite or create).</td></tr></tbody></table><h3 id="sourcewriteresponse" tabindex="-1">SourceWriteResponse <a class="header-anchor" href="#sourcewriteresponse" aria-label="Permalink to &quot;SourceWriteResponse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code></td><td>string</td><td>yes</td><td>Project-relative file path.</td></tr><tr><td><code>module</code></td><td>string</td><td>yes</td><td>Dotted module path the file imports as.</td></tr><tr><td><code>etag</code></td><td>string</td><td>yes</td><td>MD5 of the written content.</td></tr><tr><td><code>created</code></td><td>boolean</td><td>yes</td><td>True when the file did not previously exist.</td></tr></tbody></table><h3 id="validationerror" tabindex="-1">ValidationError <a class="header-anchor" href="#validationerror" aria-label="Permalink to &quot;ValidationError&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>loc</code></td><td>array</td><td>yes</td><td></td></tr><tr><td><code>msg</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>type</code></td><td>string</td><td>yes</td><td></td></tr><tr><td><code>input</code></td><td>any</td><td>no</td><td></td></tr><tr><td><code>ctx</code></td><td>object</td><td>no</td><td></td></tr></tbody></table><h3 id="versionmethod" tabindex="-1">VersionMethod <a class="header-anchor" href="#versionmethod" aria-label="Permalink to &quot;VersionMethod&quot;">​</a></h3><p>A <code>version_&amp;lt;name&gt;</code> method, invoked compactly as <code>~name(args)</code>.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>yes</td><td>Version name; use as ~name in a version list.</td></tr><tr><td><code>signature</code></td><td>string</td><td>yes</td><td>Call signature, e.g. &#39;(path)&#39; or &#39;(*, mode, backbone)&#39;.</td></tr><tr><td><code>doc</code></td><td>any</td><td>no</td><td>Docstring, if present.</td></tr><tr><td><code>source_line</code></td><td>any</td><td>no</td><td>1-based line in the module&#39;s source file.</td></tr></tbody></table><h3 id="wsframe" tabindex="-1">WSFrame <a class="header-anchor" href="#wsframe" aria-label="Permalink to &quot;WSFrame&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>type</code></td><td>string</td><td>yes</td><td>Value of the frame&#39;s <code>type</code> field.</td></tr><tr><td><code>direction</code></td><td>string</td><td>yes</td><td>&quot;client→server&quot;, &quot;server→client&quot;, or &quot;either&quot;.</td></tr><tr><td><code>summary</code></td><td>string</td><td>yes</td><td>One-line purpose of the frame.</td></tr><tr><td><code>fields</code></td><td>FrameField[]</td><td>no</td><td>Frame-specific fields beyond type/id.</td></tr></tbody></table><h3 id="widgetinfo" tabindex="-1">WidgetInfo <a class="header-anchor" href="#widgetinfo" aria-label="Permalink to &quot;WidgetInfo&quot;">​</a></h3><p>Frontend descriptor for an interface that ships a widget.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Req</th><th>Description</th></tr></thead><tbody><tr><td><code>meta</code></td><td>object</td><td>no</td><td>Opaque widget_meta; machinable never parses it.</td></tr><tr><td><code>esm_url</code></td><td>string</td><td>yes</td><td>URL serving the widget ES module.</td></tr><tr><td><code>css_url</code></td><td>any</td><td>no</td><td>URL serving the widget CSS, or null.</td></tr></tbody></table>',138)])])}const p=d(a,[["render",n]]);export{b as __pageData,p as default};
